SELECT COUNT(DISTINCT P.PK) AS TOTAL FROM SERVIDOR_PROJ SP JOIN SERVIDOR S ON S.PK_SIAPE = SP.FK_SIAPE JOIN PROJ P ON P.PK = SP.FK_PROJ WHERE LOWER(SP.PAPEL) = LOWER('participante') AND LOWER(S.GENERO) = LOWER('feminino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('inh') AND LOWER(P.TIPO_PROJETO) = LOWER('ensino') AND LOWER(COALESCE(P.AREA_CONHECIMENTO, '')) LIKE '%matem%' AND P.DATA_INICIO <= DATE('now') AND P.DATA_TERMINO >= CAST(DATE('now', '-5 years') AS DATE)